/**
 * @generated by @flusk/cli — cli-command recipe
 * CLI command: flusk alerts-setup
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { getDb } from '@flusk/resources';

export const alertsSetupCommand = new Command('alerts-setup')
  .description('Configure an alert channel')
  .requiredOption('--name <name>', 'Channel name')
  .requiredOption('--type <type>', 'Provider type (pagerduty|slack|discord|webhook|email)')
  .requiredOption('--config <json>', 'Provider config as JSON')
  .option('--severity <level>', 'Minimum severity (critical|warning|info)', 'warning')
  .action(async (opts) => {
    const db = getDb();
    const { AlertChannelRepository } = await import('@flusk/resources');

    let config: Record<string, unknown>;
    try {
      config = JSON.parse(opts.config as string);
    } catch {
      console.error(chalk.red('Invalid JSON for --config'));
      process.exit(1);
    }

    const channel = AlertChannelRepository.createAlertChannel(db, {
      name: opts.name as string,
      channelType: opts.type as 'pagerduty' | 'slack' | 'discord' | 'webhook' | 'email',
      config,
      enabled: true,
      severityFilter: (opts.severity as 'critical' | 'warning' | 'info') ?? 'warning',
    });

    console.log(chalk.green(`✅ Alert channel "${channel.name}" created (${channel.channelType})`));
  });
